DELETE FROM application_brokerage_order
WHERE order_id IN (
    SELECT id FROM brokerage_order WHERE room_id = #{roomId}
)
OR application_id IN (
    SELECT id
    FROM tutor_application
    WHERE room_id = #{roomId}
       OR (
            (sender_uid = #{teacherUid} AND receiver_uid = #{studentUid})
         OR (sender_uid = #{studentUid} AND receiver_uid = #{teacherUid})
       )
)

DELETE FROM tutor_application
WHERE room_id = #{roomId}
   OR (
        (sender_uid = #{teacherUid} AND receiver_uid = #{studentUid})
     OR (sender_uid = #{studentUid} AND receiver_uid = #{teacherUid})
   )

DELETE FROM chat_realtime_event
WHERE room_id = #{roomId}
   OR target_uid IN (#{teacherUid}, #{studentUid})
